# Two-sum in O(n) using a dict of value -> index
def two_sum(nums, target):
    seen = {}
    for i, x in enumerate(nums):
        if target - x in seen:
            return (seen[target - x], i)
        seen[x] = i
    return None

print(two_sum([2, 7, 11, 15], 9))   # (0, 1)

class HashTable:
    """Educational hash table using separate chaining."""

    def __init__(self, size: int = 8) -> None:
        self.size = size
        self.buckets: list[list[tuple]] = [[] for _ in range(size)]

    def _index(self, key) -> int:
        return hash(key) % self.size          # hash -> slot

    def put(self, key, value) -> None:
        bucket = self.buckets[self._index(key)]
        for i, (k, _) in enumerate(bucket):   # update if key exists
            if k == key:
                bucket[i] = (key, value)
                return
        bucket.append((key, value))           # else append (collision -> chain)

    def get(self, key):
        for k, v in self.buckets[self._index(key)]:
            if k == key:
                return v
        raise KeyError(key)

ht = HashTable()
ht.put("a", 1)
ht.put("b", 2)
ht.put("a", 99)        # same key -> overwrite, not duplicate
print(ht.get("a"))     # 99
print(ht.get("b"))     # 2

