# factorial: base case n <= 1, recursive case n * factorial(n-1)
def factorial(n: int) -> int:
    if n <= 1:            # base case
        return 1
    return n * factorial(n - 1)   # recursive case shrinks n

print(factorial(5))   # 120

# Naive Fibonacci recomputes the same values exponentially (O(2^n))
def fib_slow(n: int) -> int:
    if n < 2:
        return n
    return fib_slow(n - 1) + fib_slow(n - 2)

print(fib_slow(10))   # 55  (fine here, but fib_slow(40) is painfully slow)

from functools import cache

@cache                       # stores each result; each n computed once
def fib(n: int) -> int:
    if n < 2:
        return n
    return fib(n - 1) + fib(n - 2)

print(fib(40))               # 102334155 — instant, now O(n)
print(fib.cache_info())      # CacheInfo(hits=..., misses=41, ...)

# Recursion over nested structure: sum arbitrarily nested lists
def deep_sum(items) -> int:
    total = 0
    for x in items:
        if isinstance(x, list):
            total += deep_sum(x)   # recurse into sublists
        else:
            total += x
    return total

print(deep_sum([1, [2, 3, [4, 5]], 6]))   # 21

